import os
from cryptography.fernet import Fernet

# Function to generate a new encryption key
def generate_key():
    return Fernet.generate_key()

# Function to save the key to a file or environment variable
def save_key(key, path='encryption.key'):
    with open(path, 'wb') as key_file:
        key_file.write(key)

# Function to load the key from a file or environment variable
def load_key(path='encryption.key'):
    return open(path, 'rb').read()

# Function to encrypt a credit card number
def encrypt_credit_card(card_number, key):
    fernet = Fernet(key)
    encrypted_card = fernet.encrypt(card_number.encode())
    return encrypted_card

# Function to decrypt a credit card number
def decrypt_credit_card(encrypted_card, key):
    fernet = Fernet(key)
    decrypted_card = fernet.decrypt(encrypted_card).decode()
    return decrypted_card

